      numero: "11",
      caput: "Fica instituída a cobrança de taxas, nos valores constantes do Anexo desta Lei, pela prestação de serviços relativos:",
      paragrafos: [{"id":"ed:art-11-p1","numero":"1","texto":"o Os valores arrecadados destinam-se ao custeio e à manutenção das atividades do Sinarm, da Polícia Federal e do Comando do Exército, no âmbito de suas respectivas responsabilidades.","alineas":[]},{"id":"ed:art-11-p2","numero":"2","texto":"o As taxas previstas neste artigo serão isentas para os proprietários de que trata o § 5o do art. 6o e para os integrantes dos incisos I, II, III, IV, V, VI e VII do art. 6o, nos limites do regulamento desta Lei. § 2º São isentas do pagamento das taxas previstas neste artigo as pessoas e as instituições a que se referem o caput e os incisos I a VII e X e o § 5o do art. 6o desta Lei. . § 2o São isentas do pagamento das taxas previstas neste artigo as pessoas e as instituições a que se referem os incisos I a VII e X e o § 5o do art. 6o desta Lei.  § 2o São isentas do pagamento das taxas previstas neste artigo as pessoas e as instituições a que se referem os incisos I a VII e X e o § 5o do art. 6o desta Lei.","alineas":[]},{"id":"ed:art-11-p2","numero":"2","texto":"o São isentas do pagamento das taxas previstas neste artigo as pessoas e as instituições a que se referem os incisos I a VII e X e o § 5o do art. 6o desta Lei.","alineas":[]},{"id":"ed:art-11-p3","numero":"3","texto":"o São isentos de taxas o registro e a renovação do certificado de registro de arma de fogo de cano longo de alma raiada, calibre igual ou inferior a .22, e de alma lisa, calibre igual ou inferior a 16. .","alineas":[]}],
      incisos: [{"id":"ed:art-11-inc-I","numero":"I","texto":"ao registro de arma de fogo;","alineas":[]},{"id":"ed:art-11-inc-II","numero":"II","texto":"à renovação de registro de arma de fogo;","alineas":[]},{"id":"ed:art-11-inc-III","numero":"III","texto":"à expedição de segunda via de registro de arma de fogo;","alineas":[]},{"id":"ed:art-11-inc-IV","numero":"IV","texto":"à expedição de porte federal de arma de fogo;","alineas":[]},{"id":"ed:art-11-inc-V","numero":"V","texto":"à renovação de porte de arma de fogo;","alineas":[]},{"id":"ed:art-11-inc-VI","numero":"VI","texto":"à expedição de segunda via de porte federal de arma de fogo.","alineas":[]}],
      referencias: [],
