      paragrafos: [{"id":"ed:art-16-púnico","numero":"único","texto":"Nas mesmas penas incorre quem:","alineas":[]},{"id":"ed:art-16-p1","numero":"1","texto":"Nas mesmas penas incorre quem:","alineas":[]},{"id":"ed:art-16-p2","numero":"2","texto":"Se as condutas descritas no caput e no § 1º deste artigo envolverem arma de fogo de uso proibido, a pena é de reclusão, de 4 (quatro) a 12 (doze) anos.","alineas":[]}],
      incisos: [{"id":"ed:art-16-inc-I","numero":"I","texto":"suprimir ou alterar marca, numeração ou qualquer sinal de identificação de arma de fogo ou artefato;","alineas":[]},{"id":"ed:art-16-inc-II","numero":"II","texto":"modificar as características de arma de fogo, de forma a torná-la equivalente a arma de fogo de uso proibido ou restrito ou para fins de dificultar ou de qualquer modo induzir a erro autoridade policial, perito ou juiz;","alineas":[]},{"id":"ed:art-16-inc-III","numero":"III","texto":"possuir, detiver, fabricar ou empregar artefato explosivo ou incendiário, sem autorização ou em desacordo com determinação legal ou regulamentar;","alineas":[]},{"id":"ed:art-16-inc-IV","numero":"IV","texto":"portar, possuir, adquirir, transportar ou fornecer arma de fogo com numeração, marca ou qualquer outro sinal de identificação raspado, suprimido ou adulterado;","alineas":[]},{"id":"ed:art-16-inc-V","numero":"V","texto":"vender, entregar ou fornecer, ainda que gratuitamente, arma de fogo, acessório, munição ou explosivo a criança ou adolescente; e","alineas":[]},{"id":"ed:art-16-inc-VI","numero":"VI","texto":"produzir, recarregar ou reciclar, sem autorização legal, ou adulterar, de qualquer forma, munição ou explosivo.","alineas":[]}],
